pub struct ThreatWindow {
    events: Vec<(i64, String, f32, f32)>, // (timestamp_secs, hero_name, x, y)
}

impl ThreatWindow {
    /// Create a new empty threat window
    pub fn new() -> Self {
        ThreatWindow { events: Vec::new() }
    }

    /// Record a new event at `ts` for `hero` at position `(x, y)`
    pub fn record(&mut self, ts: i64, hero: &str, x: f32, y: f32) {
        self.events.push((ts, hero.to_string(), x, y));
    }

    /// Return hero names seen within `radius` units of `center`
    /// AND seen within the last `window_secs` seconds (relative to `now`)
    /// Deduplicated, sorted alphabetically.
    pub fn threats_near(&self, now: i64, center: (f32, f32), radius: f32, window_secs: i64) -> Vec<String> {
        let mut seen_heroes = Vec::new();

        // Iterate over all events
        for &(ts, hero_name, x, y) in &self.events {
            // Check time constraint first (fast rejection)
            if ts < now - window_secs {
                continue;
            }

            // Calculate Euclidean distance squared to avoid sqrt until necessary
            let dx = center.0 - x;
            let dy = center.1 - y;
            let dist_sq = dx * dx + dy * dy;

            if dist_sq <= radius * radius {
                seen_heroes.push(hero_name);
            }
        }

        // Sort alphabetically and deduplicate
        seen_heroes.sort_unstable();
        seen_heroes.dedup();
        seen_heroes
    }

    /// Evict events older than `max_age_secs` to bound memory
    pub fn evict_old(&mut self, now: i64, max_age_secs: i64) {
        // Keep only events where ts >= now - max_age_secs
        let cutoff = now - max_age_secs;
        self.events.retain(|&(ts, _, _, _)| ts >= cutoff);
    }
}

