    /// AND seen within the last `window_secs` seconds (relative to `now`)
    /// Deduplicated, sorted alphabetically.
    pub fn threats_near(
        &self,
        now: i64,
        center: (f32, f32),
        radius: f32,
        window_secs: i64,
    ) -> Vec<String> {
        let mut near_heroes = HashSet::new();

        for &(ts, hero, x, y) in &self.events {
            // 1. Temporal Check (Window)
            if ts < now - window_secs {
