            continue;
        }

        let dx = x - cx;
        let dy = y - cy;
        if dx * dx + dy * dy <= radius * radius {
            heroes.insert(name);
        }
    }

    // Convert to sorted Vec for alphabetical order
    heroes.into_iter().collect::<Vec<_>>().sort();
    heroes
}
