}

impl ThreatWindow {
    /// Creates a new empty ThreatWindow
    pub fn new() -> Self {
        Self {
            events: Vec::new(),
        }
    }

    /// Records a new threat event
    pub fn record(&mut self, ts: i64, hero: &str, x: f32, y: f32) {
        self.events.push((ts, hero.to_string(), x, y));
    }

    /// Return hero names seen within `radius` units of `center`
    /// AND seen within the last `window_secs` seconds (relative to `now`)
    /// Deduplicated, sorted alphabetically.
    pub fn threats_near(&self, now: i64, center: (f32, f32), radius: f32, window_secs: i64) -> Vec<String> {
        let mut results: Vec<String> = self.events
            .iter()
            .filter(|(ts, _, x, y)| {
                // Check if the event is within the time window
                let is_recent = *ts >= (now - window_secs);

                // Calculate Euclidean distance: sqrt((x2-x1)^2 + (y2-y1)^2)
                let dx = x - center.0;
                let dy = y - center.1;
                let distance = (dx * dx + dy * dy).sqrt();
                let is_near = distance <= radius;

                is_recent && is_near
            })
            .map(|(_, name, _, _)| name.clone())
            .collect();

        // Sort alphabetically
        results.sort();
        // Deduplicate names (e.g., if the same hero was spotted twice in the window)
        results.dedup();

        results
    }

    /// Evict events older than `max_age_secs` to bound memory
    pub fn evict_old(&mut self, now: i64, max_age_secs: i64) {
        let threshold = now - max_age_secs;
        // retain keeps elements where the closure returns true
        self.events.retain(|(ts, _, _, _)| *ts >= threshold);
    }
}

